// ╔══════════════════════════════════════════════════════╗
// ║         GLOBAL CONFIG — centralized configuration       ║
// ╚══════════════════════════════════════════════════════╝
// 
// SECURITY NOTES:
// 1. Store sensitive credentials in n8n credentials manager
// 2. Use environment variables for production deployments
// 3. Rotate API keys regularly
// 4. Implement proper access controls

const CONFIG = {
  // Jira Configuration
  JIRA: {
    BASE_URL: "https://neuralcodex2.atlassian.net",
    PROJECT_KEY: "SCRUM",
    // Auth should come from n8n credentials: {{ $credentials.jiraApi.accessToken }}
    AUTH_CREDENTIAL_NAME: "jiraApi",
    DEFAULT_FIELDS: "summary,status,assignee,priority,duedate,description,reporter,created,updated,issuetype,comment",
    TIMEOUT: 10000
  },

  // AI Configuration
  AI: {
    PROVIDER: "gemini",
    MODEL: "gemini-2.5-flash",
    API_KEY: "{{ $credentials.googleApi.apiKey }}", // Use n8n credentials
    TEMPERATURE: 0.1,
    MAX_TOKENS: 2000,
    TIMEOUT: 15000
  },

  // Slack Configuration
  SLACK: {
    CHANNEL_ID: "C0AE7UX1X47",
    CREDENTIAL_NAME: "slackApi",
    DEFAULT_CHANNEL: "task-update",
    STANDUP_CHANNEL: "all-codex-neural"
  },

  // Google Sheets Configuration
  GOOGLE_SHEETS: {
    DOCUMENT_ID: "1NHq2tsEB957RCGnQhiZIgFCl-Bv5nBOZH58Ocu98w-g",
    CREDENTIAL_NAME: "googleApi",
    SHEETS: {
      AUDIT_LOG: "AuditLog",
      REMINDERS: "Reminders"
    }
  },

  // Gmail Configuration
  GMAIL: {
    CREDENTIAL_NAME: "googleApi",
    FROM_EMAIL: "noreply@yourcompany.com"
  },

  // Business Logic Configuration
  BUSINESS: {
    TIMEZONE_OFFSET_MINUTES: 345, // UTC+5:45 Kathmandu
    ESCALATION_HOURS: 48,
    REMINDER_RETRY_LIMIT: 3,
    MAX_CONVERSATION_HISTORY: 10,
    MAX_MESSAGE_LENGTH: 2000,
    REMINDER_CHECK_INTERVAL_MINUTES: 5,
    ESCALATION_CHECK_INTERVAL_HOURS: 2
  },

  // API Endpoints
  ENDPOINTS: {
    GEMINI: "https://generativelanguage.googleapis.com/v1beta/models",
    JIRA_API: "/rest/api/3",
    JIRA_TRANSITIONS: "/rest/api/3/issue/{issueKey}/transitions",
    JIRA_ASSIGN: "/rest/api/3/issue/{issueKey}/assignee",
    JIRA_SEARCH: "/rest/api/3/search/jql",
    JIRA_PROJECTS: "/rest/api/3/project"
  },

  // Status Mappings
  STATUS_MAPPINGS: {
    CANONICAL: {
      'done': ['done', 'complete', 'completed', 'close', 'closed', 'resolve', 'resolved', 'finish', 'finished'],
      'in progress': ['in progress', 'in_progress', 'start', 'working', 'begin', 'progress'],
      'in review': ['in review', 'in_review', 'review', 'reviewing', 'under review'],
      'blocked': ['blocked', 'block', 'stuck', 'impediment', 'impeded'],
      'cancelled': ['cancelled', 'canceled', 'cancel', 'wont do', "won't do", 'wont fix'],
      'to do': ['to do', 'todo', 'backlog', 'open', 'reopen']
    },
    BLOCKER_KEYWORDS: ['block', 'impediment', 'impeded'],
    OVERDUE_KEYWORDS: ['overdue', 'late', 'past due', 'missed deadline', 'outstanding']
  },

  // Intent Definitions
  INTENTS: {
    TRACK_STATUS: 'Track project/task status, progress, overdue items',
    SET_REMINDER: 'Set time-based reminders for tasks/projects',
    UPDATE_TASK: 'Change task status, assign, add comments',
    VIEW_DASHBOARD: 'Show overview of all projects',
    ASSIGN_TASK: 'Delegate tasks to team members',
    CREATE_TASK: 'Create new tasks/tickets',
    ADD_COMMENT: 'Add notes to existing tasks',
    SEARCH_TASKS: 'Find/filter tasks by criteria',
    LIST_REMINDERS: 'Show scheduled reminders',
    CANCEL_REMINDER: 'Remove scheduled reminders',
    TEAM_WORKLOAD: 'Check team capacity and task distribution',
    REPORT_BLOCKER: 'Report impediments blocking progress',
    LIST_PROJECTS: 'Show available Jira projects',
    CREATE_PROJECT: 'Create new Jira projects',
    GET_HELP: 'Display help and capabilities',
    GET_TASK_INFO: 'Get detailed information about specific tasks',
    DELETE_TASK: 'Permanently remove tasks',
    GENERAL: 'Greetings, confirmations, unclear requests'
  },

  // Schedules
  SCHEDULES: {
    DAILY_STANDUP: "0 8 * * *", // 8 AM daily
    WEEKLY_DIGEST: "0 9 * * 1", // 9 AM Monday
    REMINDER_CHECK: "*/5 * * * *", // Every 5 minutes
    ESCALATION_CHECK: "0 */2 * * *" // Every 2 hours
  },

  // Templates
  TEMPLATES: {
    ESCALATION_MESSAGE: `🚨 *Escalation Alert — Overdue Task* 🚨\n\n*Task:* {{taskKey}} — {{summary}}\n*Project:* {{project}}\n*Assigned to:* {{assignee}}\n*Due:* {{due}} ({{hoursOverdue}} hours overdue)\n*Priority:* {{priority}}\n\n⚠️ This task has NOT been updated in 48+ hours. Please follow up immediately.\n\n_Auto-escalated by Project Tracking Agent_`,

    REMINDER_EMAIL: `<h2>⏰ Project Tracking Agent — Reminder</h2><p><strong>Project:</strong> {{projectName}}</p>{{taskName ? '<p><strong>Task:</strong> ' + taskName + '</p>' : ''}}<p>You scheduled this reminder for {{reminderTime}}.</p><p><strong>Quick Actions:</strong></p><ul><li>Reply to this email or open chatbot to take action</li></ul><hr><small>Sent by Project Tracking Agent | Reminder ID: {{reminderId}}</small>`,

    REMINDER_SLACK: `⏰ *Reminder from Project Tracking Agent*\n\n📋 *Project:* {{projectName}}\n{{taskName ? '📌 *Task:* ' + taskName : ''}}\n\nYou asked me to remind you about this. Would you like to:\n• Check current status? → Reply: "Status of {{projectName}}"\n• Mark a task done? → Reply: "Mark [task] as done"\n• Set another reminder?\n\nJust reply with your request!`
  },

  // Error Messages
  ERROR_MESSAGES: {
    TASK_NOT_FOUND: 'Task {{taskKey}} not found. Please check the task key.',
    NO_PERMISSION: 'You do not have permission to perform this action.',
    INVALID_STATUS: 'Cannot move {{taskKey}} to "{{status}}".',
    USER_NOT_FOUND: 'Could not find user "{{user}}" in Jira.',
    PROJECT_CREATION_FAILED: 'Could not create project "{{projectName}}".',
    MESSAGE_TOO_LONG: 'Your message is too long (max {{maxChars}} characters).',
    EMPTY_MESSAGE: 'I didn\'t receive any message. Please type something and try again.'
  }
};

// Validation
const validateConfig = () => {
  const required = ['JIRA.BASE_URL', 'AI.MODEL', 'SLACK.CHANNEL_ID'];
  const missing = required.filter(key => {
    const keys = key.split('.');
    let value = CONFIG;
    keys.forEach(k => value = value?.[k]);
    return !value;
  });

  if (missing.length > 0) {
    console.error('Missing required configuration:', missing);
    throw new Error(`Missing config: ${missing.join(', ')}`);
  }
};

// Runtime validation
validateConfig();

return [{ 
  json: { 
    ...CONFIG,
    // Helper functions
    helpers: {
      getJiraUrl: (path) => CONFIG.JIRA.BASE_URL + CONFIG.ENDPOINTS.JIRA_API + path,
      getGeminiUrl: () => CONFIG.ENDPOINTS.GEMINI + '/' + CONFIG.AI.MODEL + ':generateContent',
      normalizeStatus: (status) => {
        const normalized = status.toLowerCase().replace(/_/g, ' ').trim();
        for (const [canonical, aliases] of Object.entries(CONFIG.STATUS_MAPPINGS.CANONICAL)) {
          if (aliases.includes(normalized) || canonical === normalized) {
            return canonical;
          }
        }
        return normalized;
      },
      formatTimestamp: () => new Date().toISOString(),
      getLocalDate: () => {
        const now = new Date();
        const offset = CONFIG.BUSINESS.TIMEZONE_OFFSET_MINUTES;
        return new Date(now.getTime() + offset * 60 * 1000);
      }
    }
  } 
}];
